import ldap

def search_users_by_username(username):
    # Initialize the LDAP connection
    ldap_conn = ldap.initialize("ldap://ldap.example.com")

    # Bind to the LDAP directory using the read-only user
    ldap_conn.bind("cn=read-only-user,dc=example,dc=com", "password")

    # Search for users with the given username
    search_result = ldap_conn.search(
        "dc=example,dc=com",
        search_scope=ldap.SCOPE_SUBTREE,
        filter="(&(objectClass=user)(username={}))".format(username)
    )

    # Return the results as a list of dictionaries
    return [entry["dn"] for entry in search_result]